using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations -------------------------------------------------

var notebook = new Notebook();

[Description("Search the web for the given query and return a list of result snippets.")]
string WebSearch([Description("The search query")] string query)
{
    Console.WriteLine($"  🔍  Searching the web for: \"{query}\"");

    // Simulated search results – swap with a real search API (Bing, Google, etc.)
    var results = query.ToLowerInvariant() switch
    {
        var q when q.Contains("quantum computing") =>
            """
            1. Quantum computing uses qubits that can exist in superposition, enabling parallel computation. (source: nature.com)
            2. Google's Willow chip achieved breakthroughs in quantum error-correction in 2024. (source: blog.google)
            3. IBM plans to deliver a 100,000-qubit system by 2033 through modular architectures. (source: ibm.com)
            4. Quantum advantage has been demonstrated for specific problems like random circuit sampling. (source: arxiv.org)
            5. Post-quantum cryptography standards were finalized by NIST in 2024 to guard against quantum attacks. (source: nist.gov)
            """,
        var q when q.Contains("artificial intelligence") || q.Contains(" ai ") || q.Contains("ai") =>
            """
            1. Large language models (LLMs) like GPT-4 have transformed natural language understanding. (source: openai.com)
            2. AI agents are autonomous systems that use tools and reasoning to accomplish tasks. (source: microsoft.com)
            3. The EU AI Act establishes a risk-based regulatory framework for AI systems. (source: europa.eu)
            4. Multimodal AI can process text, images, audio, and video simultaneously. (source: deepmind.com)
            5. AI energy consumption is a growing concern, with large training runs using megawatts of power. (source: iea.org)
            """,
        _ =>
            $"""
            1. Overview article about "{query}" covering recent developments. (source: wikipedia.org)
            2. Academic review of "{query}" with comprehensive analysis. (source: scholar.google.com)
            3. Industry report on the state of "{query}" in 2025. (source: mckinsey.com)
            """
    };

    return results;
}

[Description("Save a note to the research notebook. Use this to record important findings.")]
string SaveNote(
    [Description("Short title for the note")] string title,
    [Description("The content of the note")] string content)
{
    notebook.Add(title, content);
    Console.WriteLine($"  📝  Note saved: \"{title}\"");
    return $"Note \"{title}\" saved successfully.";
}

[Description("Retrieve all notes saved so far in the research notebook.")]
string GetNotes()
{
    var notes = notebook.GetAll();
    Console.WriteLine($"  📖  Reading notebook ({notes.Count} note(s))");
    return notes.Count == 0
        ? "The notebook is empty."
        : string.Join("\n\n", notes.Select((n, i) => $"[{i + 1}] {n.Title}\n{n.Content}"));
}

// --- Agent setup ----------------------------------------------------------

var topic = args.Length > 0 ? string.Join(' ', args) : "quantum computing";

Console.WriteLine($"Research Agent Starting...");
Console.WriteLine($"Topic: {topic}\n");

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "no-key";
var model  = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

var messages = new List<ChatMessage>
{
    new(ChatRole.System,
        """
        You are a research agent. Your job is to research a topic thoroughly and produce
        a well-structured summary. You have access to three tools:

        1. **WebSearch** – search the web for information.
        2. **SaveNote** – save important findings to your notebook.
        3. **GetNotes** – review what you have saved so far.

        Follow this workflow:
        - Search for the topic using 2-3 different queries to get broad coverage.
        - Save the most important findings as notes.
        - Review your notes, then produce a final summary.

        Be thorough but concise in your final summary.
        """),
    new(ChatRole.User,
        $"Please research the following topic and provide a comprehensive summary: {topic}")
};

// --- Agent loop -----------------------------------------------------------

Console.WriteLine("─── Agent is researching... ───\n");

var response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n─── Research Summary ───\n");
Console.WriteLine(response.Text);

if (notebook.GetAll().Count > 0)
{
    Console.WriteLine("\n─── Notebook Contents ───\n");
    foreach (var (note, idx) in notebook.GetAll().Select((n, i) => (n, i)))
        Console.WriteLine($"[{idx + 1}] {note.Title}\n    {note.Content}\n");
}

// --- Notebook helper class ------------------------------------------------

class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public void Add(string title, string content) => _notes.Add((title, content));

    public List<(string Title, string Content)> GetAll() => [.. _notes];
}

